#include <stdio.h>
#include <stdlib.h>
#define MAX_N 100005
typedef struct Node {
    int value;
    struct Node* parent;
    struct Node** children;
    int numChildren;
} Node;
Node* nodes[MAX_N];
void dfs(Node* node, int* values) {
    node->value = values[node - nodes];
    for (int i = 0; i < node->numChildren; i++) {
        dfs(node->children[i], values);
    }
}
int countDistinct(Node* node, Node* lca) {
    int count = 0;
    while (node != lca) {
        count++;
        node = node->parent;
    }
    return count;
}
int findLCA(Node* node1, Node* node2) {
    int depth1 = 0, depth2 = 0;
    Node* temp1 = node1, *temp2 = node2;
    while (temp1 != NULL) {
        depth1++;
        temp1 = temp1->parent;
    }
    while (temp2 != NULL) {
        depth2++;
        temp2 = temp2->parent;
    }
    if (depth1 > depth2) {
        while (depth1 > depth2) {
            node1 = node1->parent;
            depth1--;
        }
    } else {
        while (depth2 > depth1) {
            node2 = node2->parent;
            depth2--;
        }
    }
    while (node1 != node2) {
        node1 = node1->parent;
        node2 = node2->parent;
    }
    return node1;
}
int main() {
    int N, Q;
    scanf("%d %d", &N, &Q);
    int values[N];
    for (int i = 0; i < N; i++) {
        scanf("%d", &values[i]);
    }
    for (int i = 0; i < N - 1; i++) {
        int u, v;
        scanf("%d %d", &u, &v);
        Node* nodeU = nodes[u - 1];
        Node* nodeV = nodes[v - 1];
        nodeU->children[nodeU->numChildren++] = nodeV;
        nodeV->parent = nodeU;
    }
    dfs(nodes[0], values);
    for (int i = 0; i < Q; i++) {
        int type;
        scanf("%d", &type);
        if (type == 1) {
            int u, v;
            scanf("%d %d", &u, &v);
            Node* nodeU = nodes[u - 1];
            Node* nodeV = nodes[v - 1];
            Node* lca = findLCA(nodeU, nodeV);
            int count = countDistinct(nodeU, lca) + countDistinct(nodeV, lca) + 1;
            printf("%d\n", count);
        } else if (type == 2) {
            int v, y;
            scanf("%d %d", &v, &y);
            nodes[v - 1]->value = y;
        }
    }
    return 0;
}

