        for (Node child : node.children) {
            dfs(child, values);
        }
    }
    public static int countDistinct(Node node, Node lca) {
        int count = 0;
        while (node != lca) {
            count++;
            node = node.parent;
        }
        return count;
    }
    public static Node findLCA(Node node1, Node node2) {
        int depth1 = 0, depth2 = 0;
        Node temp1 = node1, temp2 = node2;
        while (temp1 != null) {
            depth1++;
            temp1 = temp1.parent;
        }
        while (temp2 != null) {
            depth2++;
            temp2 = temp2.parent;
        }
        if (depth1 > depth2) {
            while (depth1 > depth2) {
                node1 = node1.parent;
                depth1--;
            }
        } else {
            while (depth2 > depth1) {
                node2 = node2.parent;
                depth2--;
            }
        }
        while (node1 != node2) {
            node1 = node1.parent;
            node2 = node2.parent;
        }
        return node1;
    }
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int N = scanner.nextInt();
        int Q = scanner.nextInt();
        int[] values = new int[N];
        for (int i = 0; i < N; i++) {
            values[i] = scanner.nextInt();
        }
        nodes = new Node[N];
        for (int i = 0; i < N; i++) {
            nodes[i] = new Node();
        }
        for (int i = 0; i < N - 1; i++) {
            int u = scanner.nextInt() - 1;
            int v = scanner.nextInt() - 1;
            nodes[u].children.add(nodes[v]);
            nodes[v].parent = nodes[u];
        }
        dfs(nodes[0], values);
        for (int i = 0; i < Q; i++) {
            int type = scanner.nextInt();
            if (type == 1) {
                int u = scanner.nextInt() - 1;
