function dfs(node, values) {
    node.value = values[node.value - 1];
    for (let child of node.children) {
        dfs(child, values);
    }
}
function countDistinct(node, lca) {
    let count = 0;
    while (node !== lca) {
        count++;
        node = node.parent;
    }
    return count;
}
function findLCA(node1, node2) {
    let depth1 = 0, depth2 = 0;
    let temp1 = node1, temp2 = node2;
    while (temp1) {
        depth1++;
        temp1 = temp1.parent;
    }
    while (temp2) {
        depth2++;
        temp2 = temp2.parent;
    }
    if (depth1 > depth2) {
        while (depth1 > depth2) {
            node1 = node1.parent;
            depth1--;
        }
    } else {
        while (depth2 > depth1) {
            node2 = node2.parent;
            depth2--;
        }
